const body = $json.body ?? $json;

if (body.tipo !== 'contacto_web') {
  throw new Error(`Tipo de solicitud no soportado: ${body.tipo}`);
}

const requiredFields = ['nombre', 'email', 'asunto', 'mensaje'];

for (const field of requiredFields) {
  if (body[field] === undefined || body[field] === null || String(body[field]).trim() === '') {
    throw new Error(`Campo obligatorio vacío: ${field}`);
  }
}

const escapeHtml = (value) => {
  return String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
};

const nombre = String(body.nombre).trim();
const email = String(body.email).trim();
const asunto = String(body.asunto).trim();
const mensaje = String(body.mensaje).trim();

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

if (!emailRegex.test(email)) {
  throw new Error('Email no válido');
}

const origen = body.origen || 'sabor-y-salsa-web';
const enviadoEn = body.enviado_en || new Date().toISOString();

const asuntoEmailRestaurante = `Nuevo mensaje de contacto - ${asunto}`;

const cuerpoEmailRestauranteHtml = `
<div style="font-family: Arial, sans-serif; font-size: 15px; color: #222; line-height: 1.5;">
  <h2 style="margin: 0 0 16px 0; color: #111;">
    Nuevo mensaje de contacto
  </h2>

  <p style="margin: 0 0 16px 0;">
    Se ha recibido un nuevo mensaje desde la web de <strong>Sabor y Salsa</strong>.
  </p>

  <table style="border-collapse: collapse; width: 100%; max-width: 650px; margin-bottom: 20px;">
    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7; width: 160px;">
        <strong>Nombre</strong>
      </td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">
        ${escapeHtml(nombre)}
      </td>
    </tr>

    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7;">
        <strong>Email</strong>
      </td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">
        <a href="mailto:${escapeHtml(email)}">${escapeHtml(email)}</a>
      </td>
    </tr>

    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7;">
        <strong>Asunto</strong>
      </td>
      <td style="padding: 8px 12px; border: 1px solid #ddd;">
        ${escapeHtml(asunto)}
      </td>
    </tr>

    <tr>
      <td style="padding: 8px 12px; border: 1px solid #ddd; background: #f7f7f7; vertical-align: top;">
        <strong>Mensaje</strong>
      </td>
      <td style="padding: 8px 12px; border: 1px solid #ddd; white-space: pre-line;">
        ${escapeHtml(mensaje)}
      </td>
    </tr>
  </table>

  <p style="margin: 0 0 8px 0;">
    <strong>Origen:</strong> ${escapeHtml(origen)}
  </p>

  <p style="margin: 0 0 20px 0;">
    <strong>Enviado en:</strong> ${escapeHtml(enviadoEn)}
  </p>

  <div style="padding: 12px 16px; background: #fff7e6; border: 1px solid #ffd591; border-radius: 6px;">
    <strong>Siguiente paso:</strong><br>
    Responder al cliente desde el correo del restaurante.
  </div>
</div>
`.trim();

const asuntoConfirmacionCliente = `Hemos recibido tu mensaje - Sabor y Salsa`;

const cuerpoConfirmacionClienteHtml = `
<div style="font-family: Arial, sans-serif; font-size: 15px; color: #222; line-height: 1.5;">
  <h2 style="margin: 0 0 16px 0; color: #111;">
    Hemos recibido tu mensaje
  </h2>

  <p>Hola ${escapeHtml(nombre)},</p>

  <p>
    Gracias por contactar con <strong>Sabor y Salsa</strong>.
    Hemos recibido tu mensaje correctamente y te responderemos lo antes posible.
  </p>

  <div style="padding: 12px 16px; background: #f7f7f7; border: 1px solid #ddd; border-radius: 6px; margin: 18px 0;">
    <strong>Asunto:</strong> ${escapeHtml(asunto)}<br><br>
    <strong>Mensaje enviado:</strong><br>
    <span style="white-space: pre-line;">${escapeHtml(mensaje)}</span>
  </div>

  <p style="margin-top: 20px;">
    Un saludo,<br>
    <strong>Sabor y Salsa</strong>
  </p>
</div>
`.trim();

return [
  {
    json: {
      tipo: 'contacto_web',
      nombre,
      email,
      asunto,
      mensaje,
      origen,
      enviado_en: enviadoEn,

      email_restaurante: 'barsaborysalsa@gmail.com',

      asunto_email_restaurante: asuntoEmailRestaurante,
      cuerpo_email_restaurante_html: cuerpoEmailRestauranteHtml,

      asunto_confirmacion_cliente: asuntoConfirmacionCliente,
      cuerpo_confirmacion_cliente_html: cuerpoConfirmacionClienteHtml
    }
  }
];
